scripts.script:
function signal() {
  var out = []
  for (var i = 0; i < 40; i++) {
    var v = 50 + 22 * Math.sin(i / 4.0) + 9 * Math.sin(i / 1.4) + i * 0.4
    out.push([i, Math.round(v)])
  }
  return out
}

html.div:
Drag a labelled point to reposition it
{{ charts[0] }}
The chart sets chart.ink.enabled, so its point annotations are draggable: grab a labelled marker and move it. On release the new position is converted back to data coordinates and written to annotations.points[].x/y, so the annotation stays glued to that data location on later zoom or resize. Each drag fires annotationDragged. Needs the ink feature. (Set draggable:false on a single annotation to pin it.)

chart.options:
chart: {
  id: 'signal',
  type: 'line',
  height: 380,
  fontFamily: 'Helvetica, Arial, sans-serif',
  animations: { enabled: false },
  ink: { enabled: true },
  toolbar: { show: false },
  zoom: { enabled: false },
},
stroke: { width: 2, curve: 'smooth' },
colors: ['#6366f1'],
title: { text: 'Signal (drag the callouts)', align: 'left' },
xaxis: { type: 'numeric', title: { text: 'Sample' } },
yaxis: { title: { text: 'Value' } },
annotations: {
  points: [
    {
      x: 6, y: 74, id: 'peak',
      marker: { size: 7, fillColor: '#fff', strokeColor: '#6366f1', strokeWidth: 3 },
      label: { text: 'Peak', borderColor: '#6366f1', style: { color: '#fff', background: '#6366f1' } },
    },
    {
      x: 20, y: 52, id: 'dip',
      marker: { size: 7, fillColor: '#fff', strokeColor: '#ef4444', strokeWidth: 3 },
      label: { text: 'Watch', borderColor: '#ef4444', style: { color: '#fff', background: '#ef4444' } },
    },
  ],
},

vanilla-js-script:
var readout = document.getElementById('ink-readout')
chart.addEventListener('annotationDragged', function (c, o) {
  readout.textContent =
    "Moved '" + o.id + "' to x=" + Number(o.x).toFixed(2) + ', y=' + Number(o.y).toFixed(2)
})
